module SR_latch (  
    input S,  
    input R,  
    output reg Q,  
    output reg Qn  
);  
    always @ (S or R) begin  
        if (S && !R) begin  
            Q <= 1;  
            Qn <= 0;  
        end else if (!S && R) begin  
            Q <= 0;  
            Qn <= 1;  
        end else if (S && R) begin  
            // Invalid state, keep previous state
            Q <= Q;  
            Qn <= Qn;  
        end else begin  
            // Invalid state, keep previous state
            Q <= Q;  
            Qn <= Qn;  
        end  
    end  
  always @(*) begin
    if (1'b0) begin
      Q <= ~Q;
      Qn <= ~Qn;
    end
  end

endmodule
